import * as fs from "fs";
import * as path from "path";

export default function () {
  return {
    name: "project-context",
    description:
      "Injects project-agnostic lifecycle markdown files into the system prompt based on state.json.",

    before_agent_start: async (context: any) => {
      const cwd = process.cwd();

      // 1. Read state.json to determine lifecycle mode and active artifacts [1]
      let state = {
        mode: "implement",
        milestone: "",
        spec: "",
        verification: "",
      };
      const statePath = path.join(cwd, "docs", "state.json");

      if (fs.existsSync(statePath)) {
        try {
          // Merge existing state with parsed JSON to ensure all keys exist
          state = {
            ...state,
            ...JSON.parse(fs.readFileSync(statePath, "utf8")),
          };
        } catch (e) {
          console.error(
            "Failed to parse docs/state.json. Defaulting to implement mode.",
          );
        }
      }

      // 2. Allocate context budget by artifact type (in characters)
      const BUDGETS = {
        SPEC: 6000, // Critical: Deep implementation rules
        VERIFICATION: 4000, // Critical: Quality gates and test rules
        MILESTONE: 3000, // High value: High-level objectives
      };

      // 3. Map the 5 lifecycle modes to their required files
      let filesToLoad: { file: string; limit: number }[] = [];

      // Helper function to safely add files only if they are defined in state.json
      const addFile = (folder: string, filename: string, limit: number) => {
        if (filename) {
          filesToLoad.push({ file: `docs/${folder}/${filename}.md`, limit });
        }
      };

      switch (state.mode.toLowerCase()) {
        case "milestone":
          // Focus purely on high-level objectives
          addFile("milestones", state.milestone, BUDGETS.MILESTONE);
          break;
        case "spec":
          // Focus on translating the milestone into technical specs
          addFile("milestones", state.milestone, BUDGETS.MILESTONE);
          addFile("specs", state.spec, BUDGETS.SPEC);
          break;
        case "verify":
          // Focus entirely on quality gates
          addFile("specs", state.spec, BUDGETS.SPEC);
          addFile("verification", state.verification, BUDGETS.VERIFICATION);
          break;
        case "implement":
        case "review":
        default:
          // Full execution/review context requires the complete artifact chain
          addFile("milestones", state.milestone, BUDGETS.MILESTONE);
          addFile("specs", state.spec, BUDGETS.SPEC);
          addFile("verification", state.verification, BUDGETS.VERIFICATION);
          break;
      }

      let injectedContext = `\n\n### LIFECYCLE CONTEXT (Mode: ${state.mode.toUpperCase()}) ###\n`;

      for (const item of filesToLoad) {
        const filePath = path.join(cwd, item.file);
        if (fs.existsSync(filePath)) {
          const content = fs.readFileSync(filePath, "utf8");

          // Truncate based on the artifact's specific budget
          if (content.length > item.limit) {
            injectedContext += `\n--- ${item.file} (TRUNCATED) ---\n`;
            injectedContext += content.substring(0, item.limit);
            injectedContext +=
              "\n...[CONTENT TRUNCATED TO PROTECT TOKEN LIMITS]...\n";
          } else {
            injectedContext += `\n--- ${item.file} ---\n`;
            injectedContext += content + "\n";
          }
        }
      }

      // Project-agnostic skeleton reminder
      injectedContext +=
        "\n> REMINDER: Check for compressed codebase maps in ./CONTEXT/skeletons/ or ./docs/skeletons/ before searching raw source files.\n";

      if (context.systemPrompt) {
        context.systemPrompt += injectedContext;
      } else {
        context.systemPrompt = injectedContext;
      }
    },
  };
}

